package com.schoolbus.controller;
import com.schoolbus.dto.request.AiChatRequest; import com.schoolbus.dto.response.ApiResponse; import jakarta.validation.Valid; import java.util.*; import org.springframework.core.env.Environment; import org.springframework.http.*; import org.springframework.web.client.RestClient; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/ai") public class AiChatController {
 private final Environment env; public AiChatController(Environment env){this.env=env;}
 @PostMapping("/chat") public ApiResponse<?> chat(@Valid @RequestBody AiChatRequest r){String key=env.getProperty("OPENAI_API_KEY");String answer=rules(r.message());if(key!=null&&!key.isBlank())try{Map<?,?> response=RestClient.create("https://api.openai.com").post().uri("/v1/chat/completions").header(HttpHeaders.AUTHORIZATION,"Bearer "+key).contentType(MediaType.APPLICATION_JSON).body(Map.of("model","gpt-4o-mini","max_tokens",180,"messages",List.of(Map.of("role","system","content","Give concise school SIS help; never expose private data."),Map.of("role","user","content",r.message())))).retrieve().body(Map.class);Object choices=response==null?null:response.get("choices");if(choices instanceof List<?> list&&!list.isEmpty()&&list.get(0) instanceof Map<?,?> c&&c.get("message") instanceof Map<?,?> message&&message.get("content")!=null)answer=message.get("content").toString();}catch(Exception ignored){}return ApiResponse.success(Map.of("reply",answer,"role",r.roleHint()==null?"authenticated":r.roleHint(),"provider",key==null||key.isBlank()?"rules":"openai-or-rules-fallback"));}
 private String rules(String message){String m=message.toLowerCase(Locale.ROOT);return m.contains("timetable")?"Open the timetable section to view class periods and rooms.":m.contains("fee")?"Check Fees for due dates, invoice status, and payment details.":m.contains("bus")||m.contains("track")?"Use the bus tracking screen for the assigned route and live vehicle status.":m.contains("leave")?"Use Leave Requests to submit leave dates and monitor approval.":m.contains("notice")?"Check Notices for school announcements and updates.":"I can help with timetable, fees, bus tracking, leave requests, and notices.";}
}
